const rows = $input.all().map(i => i.json).filter(r => r.run_date && r.query_id);

const dates = [...new Set(rows.map(r => r.run_date))].sort().reverse();
const cur = dates[0], prev = dates[1] || null;
const curRows  = rows.filter(r => r.run_date === cur);
const prevRows = prev ? rows.filter(r => r.run_date === prev) : [];

const isYes = r => String(r.mentioned).toUpperCase() === 'YES';
const parse = v => { try { return JSON.parse(v || '[]'); } catch (e) { return []; } };

// ---- 1. Mention rate per intent bucket (audit KPI #1) ----
const BUCKETS = ['brand', 'category', 'comparison', 'problem'];
// Audit baseline for the Claude engine (14 Jul 2026, appendix A3)
const BASELINE = { brand: [6,6], category: [2,7], comparison: [1,4], problem: [0,3] };

const rate = (rs, b) => {
  const s = rs.filter(r => r.intent === b);
  return { m: s.filter(isYes).length, t: s.length };
};
const buckets = BUCKETS.map(b => {
  const c = rate(curRows, b), p = prev ? rate(prevRows, b) : null;
  return { bucket: b, cur: `${c.m}/${c.t}`,
           prev: p ? `${p.m}/${p.t}` : '—',
           baseline: `${BASELINE[b][0]}/${BASELINE[b][1]}`,
           delta: p ? c.m - p.m : 0 };
});
const overallCur = curRows.filter(isYes).length;

// ---- 2. Share of voice vs key competitors (audit KPI #2) ----
const SOV = ['Pixformance', 'EGYM', 'milon', 'Proxomed', 'HUR', 'Technogym'];
const sov = SOV.map(bn => ({
  brand: bn,
  answers: curRows.filter(r => parse(r.brands).some(x => String(x).toLowerCase().includes(bn.toLowerCase()))).length
}));

// ---- 3. Status flips (alert trigger) ----
const prevMap = Object.fromEntries(prevRows.map(r => [r.query_id, isYes(r)]));
const flips = prev ? curRows
  .filter(r => r.query_id in prevMap && prevMap[r.query_id] !== isYes(r))
  .map(r => ({ id: r.query_id, dir: isYes(r) ? 'GAINED ✅' : 'LOST 🔴', q: r.query })) : [];

// ---- 4. New competitor brands in answers (alert trigger) ----
const brandSet = rs => new Set(rs.flatMap(r => parse(r.brands).map(x => String(x))));
const newBrands = prev ? [...brandSet(curRows)].filter(b => !brandSet(prevRows).has(b)) : [];

// ---- 5. New cited source domains (audit KPI #3 — do our placements enter?) ----
const domains = rs => new Set(rs.flatMap(r => parse(r.cited_sources))
  .map(u => { try { return new URL(u).hostname.replace(/^www\./, ''); } catch (e) { return null; } })
  .filter(Boolean));
const newDomains = prev ? [...domains(curRows)].filter(d => !domains(prevRows).has(d)) : [];
const newThirdParty = newDomains.filter(d => !d.includes('pixformance'));

// ---- Alert logic ----
const lostFlips = flips.filter(f => f.dir.startsWith('LOST'));
const alert = lostFlips.length > 0 || newBrands.length >= 3;
const subject = (alert ? '⚠️ ' : '✅ ') +
  `GEO Monitor ${cur} — ${overallCur}/${curRows.length} mentions` +
  (flips.length ? ` · ${flips.length} flip(s)` : '');

// ---- Email body (HTML) ----
const row = c => `<tr>${c.map(x => `<td style="padding:4px 10px;border:1px solid #ddd">${x}</td>`).join('')}</tr>`;
let html = `<h2>GEO Monitor — ${cur}</h2>
<p>Engine: claude-api · vs previous run: ${prev || 'first run'}</p>
<h3>Mention rate by intent</h3>
<table style="border-collapse:collapse">${row(['Bucket','This week','Last week','Audit baseline','Δ'])}
${buckets.map(b => row([b.bucket, b.cur, b.prev, b.baseline, (b.delta>0?'+':'')+b.delta])).join('')}</table>
<h3>Share of voice (answers naming each brand)</h3>
<table style="border-collapse:collapse">${sov.map(s => row([s.brand, s.answers])).join('')}</table>`;
if (flips.length)      html += `<h3>Status flips</h3><ul>${flips.map(f=>`<li><b>${f.dir}</b> — ${f.id}: ${f.q}</li>`).join('')}</ul>`;
if (newBrands.length)  html += `<h3>New brands in answers</h3><p>${newBrands.join(' · ')}</p>`;
if (newThirdParty.length) html += `<h3>New third-party sources cited</h3><p>${newThirdParty.join(' · ')} ← check if our placements are landing</p>`;
html += `<p style="color:#888">Baseline = audit of 14 Jul 2026. Single runs are directional; watch the trendline.</p>`;

return [{ json: { subject, html, alert, run_date: cur } }];
